1	//! Phase-A `LuaState` stub shared across all stdlib modules.
2	//!
3	//! The real `LuaState` lives in `lua-vm` (not yet compiled). For Phase A/B we
4	//! provide a single struct here so every module's call sites type-check.
5	//! Every method body is `todo!("phase-b: <name>")`.
6	//!
7	//! TODO(phase-b): replace with `pub use lua_vm::state::LuaState` once lua-vm
8	//! is compiling.
9	
10	#![allow(dead_code, unused_variables, clippy::too_many_arguments)]
11	
12	use lua_types::{
13	    arith::ArithOp,
14	    error::LuaError,
15	    gc::GcRef,
16	    string::LuaString,
17	    userdata::LuaUserData,
18	    value::LuaValue,
19	    LuaType,
20	    LuaStatus,
21	};
22	
23	/// Per-thread Lua interpreter state. Phase-A shared stub.
24	pub struct LuaState;
25	
26	/// Bare function callable from Lua. C: `lua_CFunction`.
27	#[allow(non_camel_case_types)]
28	pub type lua_CFunction = fn(&mut LuaState) -> Result<usize, LuaError>;
29	
30	/// Pseudo-index for the `i`-th upvalue of a C function.
31	/// C: `#define lua_upvalueindex(i)`
32	pub fn upvalue_index(i: i32) -> i32 {
33	    -1_001_000 - i
34	}
35	
36	/// Comparison operations (eq, lt, le). C: `LUA_OP*`.
37	#[derive(Debug, Clone, Copy, PartialEq, Eq)]
38	pub enum CompareOp {
39	    Eq,
40	    Lt,
41	    Le,
42	}
43	
44	/// Reader-callback type for `lua_load`. C: `lua_Reader`.
45	pub type LuaReader<'a> = dyn FnMut() -> Option<Vec<u8>> + 'a;
46	
47	/// Writer-callback type for `lua_dump`. C: `lua_Writer`.
48	pub type LuaWriter<'a> = dyn FnMut(&[u8]) -> Result<(), LuaError> + 'a;
49	
50	/// Debug introspection record. C: `lua_Debug`.
51	#[derive(Debug, Default, Clone)]
52	pub struct LuaDebug {
53	    pub name: Option<Vec<u8>>,
54	    pub namewhat: Vec<u8>,
55	    pub what: u8,
56	    pub source: Vec<u8>,
57	    pub short_src: Vec<u8>,
58	    pub linedefined: i32,
59	    pub lastlinedefined: i32,
60	    pub currentline: i32,
61	    pub nups: u8,
62	    pub nparams: u8,
63	    pub isvararg: bool,
64	    pub istailcall: bool,
65	    pub ftransfer: u16,
66	    pub ntransfer: u16,
67	}
