/// `debug.getmetatable(obj)` — return the metatable of `obj`, or nil if none.
///
/// C: `static int db_getmetatable(lua_State *L)`
pub(crate) fn get_metatable(state: &mut LuaState) -> Result<usize, LuaError> {
    // C: luaL_checkany(L, 1);
    state.check_arg_any(1)?;
