/// C: `LUAMOD_API int luaopen_debug(lua_State *L)`
pub fn open_debug(state: &mut LuaState) -> Result<usize, LuaError> {
    // C: luaL_newlib(L, dblib); return 1;
    state.new_lib(DBLIB)?;
    Ok(1)
}

