    let n = state.opt_arg_integer(2, 1)? as i32;
    // C: if (lua_type(L, 1) != LUA_TUSERDATA) luaL_pushfail(L);
    if state.type_at(1) != LuaType::UserData {
        state.push_fail();
        return Ok(1);
