/// C: `static int db_setuservalue(lua_State *L)`
pub(crate) fn set_uservalue(state: &mut LuaState) -> Result<usize, LuaError> {
    // C: int n = (int)luaL_optinteger(L, 3, 1);
    let n = state.opt_arg_integer(3, 1)? as i32;
