/// Name of the global environment table stored as a global itself.
/// C: `LUA_GNAME` from `lua.h`
const LUA_GNAME: &[u8] = b"_G";

/// Sentinel indicating "all return values" for call/pcall helpers.
/// C: `LUA_MULTRET = -1`
const LUA_MULTRET: i32 = -1;

