    state.new_userdata_typed(LUA_FILE_HANDLE, std::mem::size_of::<LStream>(), 0)?;
    state.set_metatable_by_name(LUA_FILE_HANDLE)?;
    Ok(())
}

/// Allocate a new regular-file handle with `io_fclose` as the close function.
/// C: `newfile(L)`.
