/// `tostring(file)` metamethod. C: `f_tostring`.
fn f_tostring(state: &mut LuaState) -> Result<usize, LuaError> {
    // C: if (isclosed(p)) lua_pushliteral(L, "file (closed)");
    // C: else lua_pushfstring(L, "file (%p)", p->f);
    let p = get_lstream(state)?;
